<script setup lang="ts">
const route = useRoute(); const router = useRouter()
const query = ref(String(route.query.q || '')); const parent = ref(String(route.query.category || '')); const child = ref(String(route.query.subcategory || '')); const condition = ref(''); const minPrice = ref<number | null>(null); const maxPrice = ref<number | null>(null); const currentPage = ref(Number(route.query.page || 1)); const pageSize = 12
const availableSubcategories = computed(() => categories.value.find(category => category.slug === parent.value)?.sub_categories || [])
const filtered = computed(() => mockProducts.value.filter(product => {
  const text = `${product.name} ${product.description} ${product.category?.name}`.toLowerCase(); const price = Number(product.price)
  return (!query.value || text.includes(query.value.toLowerCase())) && (!parent.value || product.category?.slug === parent.value || categories.value.find(c => c.slug === parent.value)?.sub_categories.some(s => s.slug === product.category?.slug)) && (!child.value || product.category?.slug === child.value) && (!condition.value || product.condition === condition.value) && (!minPrice.value || price >= minPrice.value) && (!maxPrice.value || price <= maxPrice.value)
}))
const response = computed(() => pageOf(filtered.value, currentPage.value, pageSize))
const apply = () => { currentPage.value = 1; router.replace({ query: { q: query.value || undefined, category: parent.value || undefined, subcategory: child.value || undefined, page: undefined } }) }
const clear = () => { query.value = ''; parent.value = ''; child.value = ''; condition.value = ''; minPrice.value = null; maxPrice.value = null; apply() }
const changePage = (page: number) => { currentPage.value = page; router.replace({ query: { ...route.query, page } }); window.scrollTo({ top: 0, behavior: 'smooth' }) }
</script>
<template><div class="mx-auto max-w-7xl px-5 py-10"><div class="rounded-2xl bg-slate-950 p-6 text-white md:p-8"><p class="text-sm font-bold uppercase tracking-widest text-teal-300">Marketplace</p><h1 class="mt-2 text-4xl font-black">Browse products</h1><form class="mt-6 flex max-w-3xl rounded-xl bg-white p-1" @submit.prevent="apply"><input v-model="query" class="min-w-0 flex-1 rounded-lg px-4 py-3 text-slate-900 outline-none" placeholder="What are you looking for?"/><button class="rounded-lg bg-teal-600 px-5 font-bold">Search</button></form></div><div class="mt-7 grid gap-8 lg:grid-cols-[280px_1fr]"><aside class="h-fit rounded-2xl bg-white p-5 shadow-sm ring-1 ring-slate-200 lg:sticky lg:top-28"><div class="flex items-center justify-between"><p class="font-black">Filters</p><button class="text-sm font-bold text-teal-700" @click="clear">Clear all</button></div><label class="mt-5 block text-sm font-bold">Category<select v-model="parent" class="mt-2 w-full rounded-lg border border-slate-300 p-3" @change="child = ''; apply()"><option value="">All categories</option><option v-for="category in categories" :key="category.id" :value="category.slug">{{ category.name }}</option></select></label><label class="mt-4 block text-sm font-bold">Subcategory<select v-model="child" :disabled="!parent" class="mt-2 w-full rounded-lg border border-slate-300 p-3 disabled:bg-slate-100" @change="apply"><option value="">All subcategories</option><option v-for="subcategory in availableSubcategories" :key="subcategory.id" :value="subcategory.slug">{{ subcategory.name }}</option></select></label><label class="mt-4 block text-sm font-bold">Condition<select v-model="condition" class="mt-2 w-full rounded-lg border border-slate-300 p-3" @change="apply"><option value="">Any condition</option><option value="brand new">Brand new</option><option value="used">Used</option></select></label><fieldset class="mt-5"><legend class="text-sm font-bold">Price range (₦)</legend><div class="mt-2 grid grid-cols-2 gap-2"><input v-model.number="minPrice" type="number" class="min-w-0 rounded-lg border border-slate-300 p-3" placeholder="Min" @change="apply"/><input v-model.number="maxPrice" type="number" class="min-w-0 rounded-lg border border-slate-300 p-3" placeholder="Max" @change="apply"/></div></fieldset><button class="mt-5 w-full rounded-lg border border-teal-700 py-3 text-sm font-bold text-teal-700" @click="apply">Apply filters</button></aside><div><div class="flex items-center justify-between"><p class="text-sm text-slate-500"><strong class="text-slate-900">{{ response.total }}</strong> products found</p><select class="rounded-lg border border-slate-300 p-2 text-sm"><option>Sort: Recommended</option><option>Price: Low to high</option><option>Newest arrivals</option></select></div><div v-if="response.items.length" class="mt-5 grid grid-cols-2 gap-4 md:grid-cols-3 xl:grid-cols-4"><ProductCard v-for="product in response.items" :key="product.slug" :product="product" /></div><div v-else class="mt-5 rounded-2xl border border-dashed border-slate-300 p-10 text-center"><h2 class="text-xl font-black">No products match those filters</h2><button class="mt-3 font-bold text-teal-700" @click="clear">Clear filters</button></div><AppPagination :page="response" @change="changePage" /></div></div></div></template>
